import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void smallAdditive() {
        assertEquals(3, new Solution().romanToInt("III"));
    }

    @Test
    void subtractiveIV() {
        assertEquals(4, new Solution().romanToInt("IV"));
    }

    @Test
    void subtractiveIX() {
        assertEquals(9, new Solution().romanToInt("IX"));
    }

    @Test
    void mixed() {
        assertEquals(58, new Solution().romanToInt("LVIII"));
    }

    @Test
    void complexSubtractive() {
        assertEquals(1994, new Solution().romanToInt("MCMXCIV"));
    }

    @Test
    void rangeMaximum() {
        assertEquals(3999, new Solution().romanToInt("MMMCMXCIX"));
    }

    @Test
    void roundTripInvertibility() {
        // Confirm decode(encode(n)) == n for a representative value
        // intToRoman is not on Solution, so we test the known pair directly:
        // intToRoman(1994) == "MCMXCIV" (from variant 1), romanToInt("MCMXCIV") must equal 1994
        assertEquals(1994, new Solution().romanToInt("MCMXCIV"));
        // And for the range boundary
        assertEquals(1, new Solution().romanToInt("I"));
    }
}
